def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for x in range(8, 3, -1):
                sum_inner = 0
                for y in range(1, x + 5):
                    exp_term = np.exp(-(ratio - x) * y * 0.5)
                    trig_term = np.sin(ratio * y / (x + 2)) * np.cos(ratio / (y + 1))
                    sum_inner += exp_term * trig_term / (x + y)
                priority += sum_inner * np.log1p(ratio) * 2.3
            priority += (np.tanh(ratio) * np.sin(ratio * 2.2)) ** 2 + np.sqrt(ratio)
        elif 5 < ratio <= 8:
            sum1 = 0
            for p in range(1, 20):
                for q in range(1, p + 3):
                    pow_term = ((ratio - p) ** 4)/((q + 0.7)**1.5 + 1)
                    trig = np.cos(ratio * q) + np.sin(ratio * p / (q + 1))
                    sum1 += np.tanh(pow_term) * trig * 1.5
            priority = sum1 + np.log(ratio + 1) * 12 - np.tanh(ratio - 5) * 3.2
        elif 3 <= ratio <= 5:
            s = 0
            for r in range(1, 18):
                base = ((ratio - 3) ** r) / (r * 2.2)
                trig = np.cos(r * ratio) + np.sin(r * ratio * 0.9)
                s += base * trig
            priority = s * np.cos(9 * ratio) - np.log(ratio) * 8 + np.tanh(5 - ratio) * 3.5
            for extra in range(1, 5):
                priority += np.sin(extra * ratio * i * 0.7) * ((ratio - 3) ** extra) / extra
        elif 1.2 <= ratio < 3:
            sum2 = 0
            for n in range(1, 15):
                decay = ((3 - ratio) ** n) / (n ** 2 + 1.3)
                trig = np.cos(n * ratio * 1.1) + np.sin(n * (ratio + i) * 0.8)
                sum2 += decay * trig
            priority = sum2 + np.exp(-2 / (ratio + 0.1))
            if bin_cap < item * 1.3:
                penalty = np.abs(np.cos(25 * ratio) * 3)
            else:
                penalty = np.log1p(bin_cap) * 1.7
            priority += penalty
            for m in range(1, 7):
                priority += np.sin(m * ratio * (i + 1)) * ((ratio - 1.2) ** m) / (m + 0.5)
        elif 0.5 <= ratio < 1.2:
            s = 0
            for n in range(1, 20):
                term = ((1.2 - ratio) ** n) / (n * 3.5)
                s += term * np.cos(n * item * 1.5) * np.sin(n * ratio * 2.2)
            priority = s
            if (i * int(item * 1.8)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2.5) + 2.7)
            if bin_cap < item * 0.9:
                priority += np.sqrt(item * bin_cap) * 2.8
            else:
                priority -= np.exp(-ratio * 2.5) * 3.8
            for j in range(1, 6):
                priority += ((1.2 - ratio) ** j) * np.sin(j * bin_cap * 1.1) * 0.9
        elif 0.15 <= ratio < 0.5:
            s = 0
            for k in range(1, 18):
                val = ((0.5 - ratio) ** k) / (k * 2.7) * np.cos(k * ratio * 1.6) * np.sin(k * ratio)
                s += val
            priority = s + 0.5 / (bin_cap + 2)
            if int(item * 1.7) % 5 == 0:
                priority *= 2.8
            else:
                priority /= 2.9
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.7) * 3.5
            for m in range(1, 8):
                priority += ((0.5 - ratio) ** m) / (m * 5) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 14):
                s += ((0.15 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.0) * np.cos(t * ratio * 1.4)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.6
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6.5
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.15 - ratio) ** u) / (u * 8) * np.cos(item * u * 1.1)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6.3
            for v in range(1, 5):
                priority += np.tanh(ratio * v) * np.sin(i * v * ratio * 0.7)
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5.4
            for w in range(1, 3):
                priority -= np.cos(ratio * i * w) * 0.5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.3) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 0.9) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        priorities[i] = priority
    return priorities
